#include <iostream>
#include <string>
#include <unordered_map>
#include <vector>
using namespace std;struct Item{int value,freq,time;};string run(int cap,vector<char>&k,vector<vector<int>>&ops){int clk=0;unordered_map<int,Item> cache;vector<string>res;for(int i=0;i<k.size();i++){clk++;if(k[i]=='C'){cache.clear();res.push_back("null");}else if(k[i]=='P'){int key=ops[i][0],val=ops[i][1];if(cap==0){res.push_back("null");continue;}auto it=cache.find(key);if(it!=cache.end())it->second={val,it->second.freq+1,clk};else{if(cache.size()==cap){int victim=0;Item best{0,1000000000,1000000000};bool first=true;for(auto&[kk,v]:cache)if(first||v.freq<best.freq||v.freq==best.freq&&(v.time<best.time||v.time==best.time&&kk<victim)){victim=kk;best=v;first=false;}cache.erase(victim);}cache[key]={val,1,clk};}res.push_back("null");}else{int key=ops[i][0];auto it=cache.find(key);if(it==cache.end())res.push_back("-1");else{int v=it->second.value;it->second.freq++;it->second.time=clk;res.push_back(to_string(v));}}}string out="[";for(int i=0;i<res.size();i++){if(i)out+=",";out+=res[i];}return out+"]";}int main(){ios::sync_with_stdio(false);cin.tie(nullptr);int t;if(!(cin>>t))return 0;for(int tc=0;tc<t;tc++){int cap,m;cin>>cap>>m;vector<char>k(m);vector<vector<int>>ops(m);for(int i=0;i<m;i++){string op;cin>>op;k[i]=op[0];if(op=="P"){int a,b;cin>>a>>b;ops[i]={a,b};}else if(op=="G"){int a;cin>>a;ops[i]={a};}}if(tc)cout<<"\n\n";cout<<run(cap,k,ops);}}
